import{_ as s,o as a,c as t,a2 as i}from"./chunks/framework.ChqliYsl.js";const u=JSON.parse('{"title":"Releases","description":"","frontmatter":{},"headers":[],"relativePath":"contributing/releases.md","filePath":"contributing/releases.md","lastUpdated":1781721505000}'),o={name:"contributing/releases.md"};function l(n,e,r,d,c,p){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="releases" tabindex="-1">Releases <a class="header-anchor" href="#releases" aria-label="Permalink to &quot;Releases&quot;">​</a></h1><p>AOSC releases have two version axes:</p><ul><li><strong>AOSC version</strong>: the plugin project version, such as <code>0.1.0</code>.</li><li><strong>OpenSearch compatibility line</strong>: the OpenSearch major/minor line the ZIP was built against, such as <code>2.19</code>.</li></ul><p>The plugin descriptor uses a patch-compatible semver range for the selected OpenSearch minor. For example, a ZIP built with OpenSearch <code>2.19.0</code> is intended for OpenSearch <code>2.19.x</code> unless a release note says otherwise.</p><h2 id="source-of-truth" tabindex="-1">Source of Truth <a class="header-anchor" href="#source-of-truth" aria-label="Permalink to &quot;Source of Truth&quot;">​</a></h2><p>The AOSC release version is tracked in <code>version.properties</code>:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">aosc.version</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=0.0.0-dev</span></span></code></pre></div><p><code>develop</code> intentionally uses <code>0.0.0-dev</code>. Release branches are authoritative for release versions and should carry a concrete release candidate such as:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">aosc.version</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=0.1.0-SNAPSHOT</span></span></code></pre></div><p>OpenSearch compatibility metadata is tracked per release line:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>release/os2.properties</span></span>
<span class="line"><span>release/os3.properties</span></span></code></pre></div><p>The current OpenSearch 2.x line is:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">line</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=os2</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">branch</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=releases/2.x</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">primary_version</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=2.19.0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">build_versions</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=2.15.0,2.17.0,2.19.0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">test_versions</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=2.15.0,2.17.0,2.17.1,2.19.0,2.19.3</span></span></code></pre></div><p>Release tags, asset names, documentation versions, GitHub Actions matrices, and release branch checks are derived from these files. Do not type release versions directly into the GitHub workflow.</p><h2 id="branches" tabindex="-1">Branches <a class="header-anchor" href="#branches" aria-label="Permalink to &quot;Branches&quot;">​</a></h2><p>Release branches are organized by OpenSearch major line:</p><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Branch</th><th>Purpose</th></tr></thead><tbody><tr><td><code>develop</code></td><td>Active development.</td></tr><tr><td><code>releases/2.x</code></td><td>OpenSearch 2.x maintenance and releases.</td></tr><tr><td><code>releases/3.x</code></td><td>OpenSearch 3.x maintenance and releases once supported.</td></tr></tbody></table></div><p>GitHub release publishing must run from the branch declared in the matching <code>release/&lt;line&gt;.properties</code> file. For example, the OpenSearch 2.x release publisher should only publish plugin artifacts from <code>releases/2.x</code>.</p><p>Pushing to a release branch runs validation only. Publishing is manual: run the GitHub <code>Publish Release</code> workflow from the release branch after validation is green.</p><p>Do not publish plugin releases directly from <code>develop</code>. Merge or cherry-pick the intended release content into the matching <code>releases/*</code> branch first, then release from that branch. This keeps release artifacts tied to a maintenance line instead of a moving development branch.</p><p>Release tags should include the OpenSearch major line, for example:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aosc-0.1.0-os2</span></span>
<span class="line"><span>aosc-0.1.0-os3</span></span></code></pre></div><p>Avoid ambiguous tags such as <code>v0.1.0</code> once OpenSearch 2.x and 3.x can diverge.</p><p>The publish workflow fails before building if the computed GitHub release or tag already exists. Bump <code>aosc.version</code> before publishing another release for the same OpenSearch line.</p><h2 id="release-version-lifecycle" tabindex="-1">Release Version Lifecycle <a class="header-anchor" href="#release-version-lifecycle" aria-label="Permalink to &quot;Release Version Lifecycle&quot;">​</a></h2><p>Release branches use <code>-SNAPSHOT</code> as the pre-release marker for the next intended release:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>develop:      0.0.0-dev</span></span>
<span class="line"><span>releases/2.x: 0.1.0-SNAPSHOT</span></span>
<span class="line"><span>prepare:      human commits 0.1.0-SNAPSHOT -&gt; 0.1.0</span></span>
<span class="line"><span>publish:      workflow tags 0.1.0, creates draft GitHub release, deploys docs</span></span>
<span class="line"><span>next work:    human commits 0.1.0 -&gt; 0.1.1-SNAPSHOT, 0.2.0-SNAPSHOT, or 1.0.0-SNAPSHOT</span></span></code></pre></div><p>The release workflow never commits back to the release branch. The release branch must already be in a releasable state before the workflow starts.</p><p>Manual release flow:</p><ol><li>Merge or cherry-pick the intended changes into the matching release branch.</li><li>Set <code>aosc.version=X.Y.Z-SNAPSHOT</code> while preparing and validating the release branch.</li><li>Commit <code>aosc.version=X.Y.Z</code> when the branch is ready to release.</li><li>Run <code>Publish Release</code> from the release branch.</li><li>The workflow validates the current branch state, runs full CI, creates tag <code>aosc-X.Y.Z-os2</code>, builds release ZIPs, creates a draft GitHub release, and publishes docs.</li><li>After release, commit the next <code>-SNAPSHOT</code> version to the release branch.</li></ol><p>The workflow rejects <code>develop</code> versions such as <code>0.0.0-dev</code> and release-candidate versions such as <code>0.1.0-SNAPSHOT</code>; releases must be made from <code>releases/*</code> branches using exact <code>X.Y.Z</code> versions.</p><p>Use patch, minor, and major bumps this way:</p><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Bump</th><th>Use when</th><th>Example next snapshot</th></tr></thead><tbody><tr><td>Patch</td><td>Fixes, documentation corrections, CI/release fixes, compatibility metadata corrections</td><td><code>0.1.1-SNAPSHOT</code></td></tr><tr><td>Minor</td><td>New compatible user-visible behavior, new settings, new APIs, expanded compatibility</td><td><code>0.2.0-SNAPSHOT</code></td></tr><tr><td>Major</td><td>Breaking API, behavior, state format, or operational contract changes</td><td><code>1.0.0-SNAPSHOT</code></td></tr></tbody></table></div><h2 id="opensearch-compatibility" tabindex="-1">OpenSearch Compatibility <a class="header-anchor" href="#opensearch-compatibility" aria-label="Permalink to &quot;OpenSearch Compatibility&quot;">​</a></h2><p>Each release line declares two compatibility lists:</p><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Property</th><th>Meaning</th></tr></thead><tbody><tr><td><code>build_versions</code></td><td>OpenSearch minors that receive release ZIPs.</td></tr><tr><td><code>test_versions</code></td><td>Exact OpenSearch patch versions covered by CI.</td></tr></tbody></table></div><p>For OpenSearch 2.x, AOSC currently builds release ZIPs for <code>2.15</code>, <code>2.17</code>, and <code>2.19</code>, and runs CI against <code>2.15.0</code>, <code>2.17.0</code>, <code>2.17.1</code>, <code>2.19.0</code>, and <code>2.19.3</code>.</p><p>The ZIP name intentionally uses the OpenSearch minor, for example <code>opensearch-aosc-0.1.0-opensearch-2.19.zip</code>. The plugin descriptor uses a patch-compatible semver range for that minor, so the <code>2.19</code> ZIP is intended for the <code>2.19.x</code> line unless the release notes call out an exception.</p><h2 id="github-actions-policy" tabindex="-1">GitHub Actions Policy <a class="header-anchor" href="#github-actions-policy" aria-label="Permalink to &quot;GitHub Actions Policy&quot;">​</a></h2><p>The workflow files are split by the reason a workflow runs:</p><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Workflow</th><th>File</th><th>Trigger</th><th>Publishes?</th></tr></thead><tbody><tr><td>Pull Request</td><td><code>.github/workflows/pull-request.yml</code></td><td>Pull requests targeting <code>develop</code> or <code>releases/**</code></td><td>No</td></tr><tr><td>Branch: develop</td><td><code>.github/workflows/branch-develop.yml</code></td><td>Pushes to <code>develop</code></td><td>Publishes <code>/develop/</code> docs after validation passes</td></tr><tr><td>Branch: release</td><td><code>.github/workflows/branch-release.yml</code></td><td>Pushes to <code>releases/**</code></td><td>No</td></tr><tr><td>Publish Release</td><td><code>.github/workflows/publish-release.yml</code></td><td>Manual dispatch from a release branch</td><td>Publishes GitHub release assets and release docs</td></tr><tr><td>Components</td><td><code>.github/workflows/components.yml</code></td><td>Reusable workflow only</td><td>No</td></tr></tbody></table></div><p>Pull requests run full CI automatically. Full CI builds the docs and validates every OpenSearch version in <code>test_versions</code> from <code>release/&lt;line&gt;.properties</code>.</p><p>Full CI runs these suite categories as separate jobs so failures identify the exact affected OpenSearch version and suite:</p><ul><li>fast checks</li><li>YAML REST tests</li><li>Java integration tests</li><li>2-node smoke tests</li><li>dedicated cluster-manager smoke tests</li><li>Docker smoke tests</li><li>high-shard 2-node scale tests</li></ul><p>Pushes to <code>develop</code> and <code>releases/**</code> also run full CI. Branch protection should require the stable check name:</p><ul><li><code>Full CI</code></li></ul><p>The <code>Publish Release</code> workflow runs the same full validation before it builds release ZIPs or creates a draft GitHub release.</p><h2 id="github-release-assets" tabindex="-1">GitHub Release Assets <a class="header-anchor" href="#github-release-assets" aria-label="Permalink to &quot;GitHub Release Assets&quot;">​</a></h2><p>Each GitHub release should include:</p><ul><li>one plugin ZIP per supported OpenSearch build target</li><li><code>SHA256SUMS</code></li><li>release notes with compatibility and upgrade notes</li><li>an SBOM when available</li><li>artifact provenance or attestation when available</li></ul><p>Example OpenSearch 2.x assets:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensearch-aosc-0.1.0-opensearch-2.15.zip</span></span>
<span class="line"><span>opensearch-aosc-0.1.0-opensearch-2.17.zip</span></span>
<span class="line"><span>opensearch-aosc-0.1.0-opensearch-2.19.zip</span></span>
<span class="line"><span>SHA256SUMS</span></span></code></pre></div><h2 id="building-locally" tabindex="-1">Building Locally <a class="header-anchor" href="#building-locally" aria-label="Permalink to &quot;Building Locally&quot;">​</a></h2><p>Build a ZIP for one OpenSearch version:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :aosc-plugin:bundlePlugin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Dopensearch.version=2.19.0</span></span></code></pre></div><p>Build and rename all currently supported OpenSearch 2.x ZIPs:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/build-release-zips.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> os2</span></span></code></pre></div><p>The script writes release assets to <code>build/release/</code>.</p><p>Inspect the release metadata with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/release-metadata.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> os2</span></span></code></pre></div><h2 id="documentation-site" tabindex="-1">Documentation Site <a class="header-anchor" href="#documentation-site" aria-label="Permalink to &quot;Documentation Site&quot;">​</a></h2><p>GitHub Pages uses VitePress. Pull requests build the docs as CI validation only; they do not publish the site.</p><p>The docs workflows store versioned site output on the <code>gh-pages</code> branch, then deploy the complete site with GitHub Pages Actions. The GitHub Pages repository setting should use GitHub Actions as the source.</p><p>Pushes to <code>develop</code> publish the current development docs to <code>/develop/</code> after full CI passes.</p><p>The current docs layout is:</p><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Source</th><th>Published path</th></tr></thead><tbody><tr><td><code>develop</code></td><td><code>/develop/</code></td></tr><tr><td><code>releases/2.x</code> with <code>aosc.version=0.1.0</code></td><td><code>/0.1.0-os2/</code></td></tr><tr><td><code>releases/3.x</code> with <code>aosc.version=0.1.0</code></td><td><code>/0.1.0-os3/</code> once the branch exists</td></tr></tbody></table></div><p>Release documentation is versioned by exact AOSC patch version plus OpenSearch major line. For example, <code>aosc.version=0.1.0</code> and <code>line=os2</code> publish to <code>/0.1.0-os2/</code>. A patch release such as <code>0.1.1</code> publishes separate documentation at <code>/0.1.1-os2/</code>.</p><p>Build the docs locally with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ci</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:build</span></span></code></pre></div><p>The docs deploy script owns the generated <code>versions.json</code> and root redirect on <code>gh-pages</code>; do not edit those files by hand.</p><h2 id="ci-artifacts" tabindex="-1">CI Artifacts <a class="header-anchor" href="#ci-artifacts" aria-label="Permalink to &quot;CI Artifacts&quot;">​</a></h2><p>CI uploads Gradle reports and test results only when a validation job fails. Normal CI artifacts expire after 7 days; publish workflow test artifacts expire after 14 days. Release ZIPs are not CI artifacts; they are attached to GitHub Releases.</p><h2 id="runtime-version-checks" tabindex="-1">Runtime Version Checks <a class="header-anchor" href="#runtime-version-checks" aria-label="Permalink to &quot;Runtime Version Checks&quot;">​</a></h2><p>Installed plugin versions can be checked with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;http://localhost:9200/_cat/plugins?v&#39;</span></span></code></pre></div><p>A built ZIP descriptor can be inspected with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">unzip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aosc-plugin/build/distributions/opensearch-aosc-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.zip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugin-descriptor.properties</span></span></code></pre></div><h2 id="first-public-import" tabindex="-1">First Public Import <a class="header-anchor" href="#first-public-import" aria-label="Permalink to &quot;First Public Import&quot;">​</a></h2><p>Public GitHub history starts from the OSS import. Earlier internal development history is not part of the public repository.</p>`,79)])])}const b=s(o,[["render",l]]);export{u as __pageData,b as default};
